import React from 'react';
import SectionHeading from '../SectionHeading/SectionHeading.js';
import './AboutMe.scss';


function ShowSkills() {
  const technologies = [
    {
      name:"Languages",
      content:["Python","Java","C","HTML / SCSS","JavaScript",""]
    },
    {
      name:"Frameworks",
      content:["React","Flask"]
    },
    {
      name:"Tools",
      content:["Github","Terminal","NEAT Python","Inventor","R / Octave","MATLAB"]
    },
    {
      name:"Additional Skills",
      content:["Data Structures","Algorithms","Web Hosting, Mgmt","Communication","Teaching"]
    }
  ];

  return (
    <div className="aboutme_col">
      {technologies.map(item => (
        <div className="aboutme_col_contents">
          <div className="aboutme_col_title">
              {item.name}
          </div>
          <div className="aboutme_col_b">
            {item.content.map(item2 => (
              <ul>
                <li>
                  <div className="smalltext">
                    {item2}
                  </div>
                </li>
              </ul>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
}



function AboutMe() {
  return (
    <div className="aboutme">
      <div className="aboutme_c">
        hieajhfia
        safa
      </div>
    </div>
  )
}

export default AboutMe;






